const { Manifold, label } = api;

// Box body: 20w x 12d x 10h, centered in XY, sitting on z=0
const bodyW = 20,
  bodyD = 12,
  bodyH = 10;
const body = Manifold.cube([bodyW, bodyD, bodyH], true).translate([0, 0, bodyH / 2]);

// Rounded lid: half-cylinder on top. Cylinder axis along X, radius=6, length=20.
// Half cylinder: full cylinder then cut bottom half.
const lidR = 6;
const lidCyl = Manifold.cylinder(bodyW, lidR, lidR, 48).rotate([0, 90, 0]).translate([-bodyW / 2, 0, bodyH]);
const lidCut = Manifold.cube([bodyW + 2, bodyD + 2, lidR + 1], true).translate([0, 0, bodyH - lidR - 0.5]);
const lid = lidCyl.subtract(lidCut);

// Gold horizontal straps around the body (thin bands)
// 3 vertical straps wrapping around the body sides
const strapW = 1.2,
  strapH = 0.4;
// Horizontal strap at z=3 (lower body)
const hStrap1 = Manifold.cube([bodyW + strapH * 2, bodyD + strapH * 2, strapW], true)
  .subtract(Manifold.cube([bodyW - strapH, bodyD - strapH, strapW + 0.2], true))
  .translate([0, 0, 3]);
// Horizontal strap at z=7 (upper body near lid)
const hStrap2 = Manifold.cube([bodyW + strapH * 2, bodyD + strapH * 2, strapW], true)
  .subtract(Manifold.cube([bodyW - strapH, bodyD - strapH, strapW + 0.2], true))
  .translate([0, 0, 7]);

// Vertical straps on -Y front face: left, center, right
function frontStrap(x) {
  return Manifold.cube([strapW, strapH + 0.1, bodyH + 0.2], true)
    .translate([x, -bodyD / 2 - strapH / 2, bodyH / 2]);
}
const vStrapL = frontStrap(-6);
const vStrapC = frontStrap(0);
const vStrapR = frontStrap(6);

// Lock plate on front face center — extends 1 unit into body for solid union
const lockPlate = Manifold.cube([3.5, 1.6, 3.0], true).translate([0, -bodyD / 2 - 0.8, 4.5]);
// Lock keyhole: small cylinder protrudes outward at front of plate
const keyhole = Manifold.cylinder(1.6, 0.7, 0.7, 16).rotate([90, 0, 0]).translate([0, -bodyD / 2 - 1.5, 4.2]);

// Lid straps: matching straps on the lid
// Corner trim pieces on lid top
const lidStrapL = Manifold.cube([strapW, bodyD + 1, strapH + 0.1], true).translate([-6, 0, bodyH + lidR * 0.7]);
const lidStrapR = Manifold.cube([strapW, bodyD + 1, strapH + 0.1], true).translate([6, 0, bodyH + lidR * 0.7]);

const trimParts = hStrap1.add(hStrap2).add(vStrapL).add(vStrapC).add(vStrapR)
  .add(lidStrapL).add(lidStrapR);

const chestBody = label(body, 'body');
const chestLid = label(lid, 'lid');
const trim = label(trimParts, 'trim');
const lock = label(lockPlate.add(keyhole), 'lock');

return chestBody.add(chestLid).add(trim).add(lock);
